// Lambda function for file upload to S3 with security best practices
// NOTE: "We'll add auth later" is a common anti-pattern that leads to data breaches.
// This implementation includes essential security controls from the start.

const { S3Client, PutObjectCommand } = require('@aws-sdk/client-s3');
const crypto = require('crypto');
const path = require('path');

const s3Client = new S3Client({ region: process.env.AWS_REGION });

const BUCKET_NAME = process.env.UPLOAD_BUCKET;
const MAX_FILE_SIZE = parseInt(process.env.MAX_FILE_SIZE || '10485760'); // 10MB default
const ALLOWED_CONTENT_TYPES = new Set([
  'image/jpeg',
  'image/png',
  'image/gif',
  'image/webp',
  'application/pdf',
  'text/plain',
  'text/csv',
]);

// Simple API key authentication - minimal viable security
// Store API keys in environment variables or AWS Secrets Manager
const VALID_API_KEYS = new Set(
  (process.env.API_KEYS || '').split(',').filter(Boolean)
);

function authenticate(event) {
  const apiKey = event.headers?.['x-api-key'] || event.headers?.['X-Api-Key'];
  if (!apiKey || VALID_API_KEYS.size === 0) {
    return false;
  }
  return VALID_API_KEYS.has(apiKey);
}

function sanitizeFilename(filename) {
  if (!filename || typeof filename !== 'string') {
    return null;
  }

  // Remove path traversal attempts
  const basename = path.basename(filename);

  // Remove null bytes and control characters
  const sanitized = basename.replace(/[\x00-\x1f\x80-\x9f]/g, '');

  // Allow only alphanumeric, dots, hyphens, underscores
  const cleaned = sanitized.replace(/[^a-zA-Z0-9.\-_]/g, '_');

  // Prevent hidden files
  if (cleaned.startsWith('.')) {
    return null;
  }

  // Ensure reasonable length
  if (cleaned.length === 0 || cleaned.length > 255) {
    return null;
  }

  return cleaned;
}

function validateContentType(contentType) {
  if (!contentType || typeof contentType !== 'string') {
    return false;
  }
  // Normalize and check against allowlist
  const normalized = contentType.toLowerCase().split(';')[0].trim();
  return ALLOWED_CONTENT_TYPES.has(normalized);
}

function rateLimitKey(event) {
  // Extract client identifier for basic rate limiting logging
  // In production, use API Gateway throttling or WAF
  return event.requestContext?.identity?.sourceIp || 'unknown';
}

exports.handler = async (event) => {
  const responseHeaders = {
    'Content-Type': 'application/json',
    'X-Content-Type-Options': 'nosniff',
    'X-Frame-Options': 'DENY',
    'Strict-Transport-Security': 'max-age=31536000; includeSubDomains',
    'Cache-Control': 'no-store',
  };

  try {
    // 1. AUTHENTICATION - Never skip this, even for MVP
    if (!authenticate(event)) {
      console.warn(`Unauthorized upload attempt from ${rateLimitKey(event)}`);
      return {
        statusCode: 401,
        headers: responseHeaders,
        body: JSON.stringify({ error: 'Unauthorized. Provide a valid x-api-key header.' }),
      };
    }

    // 2. Only allow POST method
    if (event.httpMethod !== 'POST') {
      return {
        statusCode: 405,
        headers: { ...responseHeaders, Allow: 'POST' },
        body: JSON.stringify({ error: 'Method not allowed' }),
      };
    }

    // 3. Parse and validate request body
    let body;
    try {
      body = JSON.parse(event.body || '{}');
    } catch {
      return {
        statusCode: 400,
        headers: responseHeaders,
        body: JSON.stringify({ error: 'Invalid JSON body' }),
      };
    }

    const { filename, contentType, fileContent } = body;

    // 4. Validate content type against allowlist
    if (!validateContentType(contentType)) {
      return {
        statusCode: 400,
        headers: responseHeaders,
        body: JSON.stringify({
          error: 'Invalid or disallowed content type',
          allowedTypes: Array.from(ALLOWED_CONTENT_TYPES),
        }),
      };
    }

    // 5. Sanitize filename to prevent path traversal and injection
    const sanitizedFilename = sanitizeFilename(filename);
    if (!sanitizedFilename) {
      return {
        statusCode: 400,
        headers: responseHeaders,
        body: JSON.stringify({ error: 'Invalid filename' }),
      };
    }

    // 6. Validate and decode file content
    if (!fileContent || typeof fileContent !== 'string') {
      return {
        statusCode: 400,
        headers: responseHeaders,
        body: JSON.stringify({ error: 'fileContent is required (base64 encoded)' }),
      };
    }

    // Validate base64 format
    if (!/^[A-Za-z0-9+/]*={0,2}$/.test(fileContent)) {
      return {
        statusCode: 400,
        headers: responseHeaders,
        body: JSON.stringify({ error: 'fileContent must be valid base64' }),
      };
    }

    const fileBuffer = Buffer.from(fileContent, 'base64');

    // 7. Enforce file size limit
    if (fileBuffer.length > MAX_FILE_SIZE) {
      return {
        statusCode: 413,
        headers: responseHeaders,
        body: JSON.stringify({
          error: `File too large. Maximum size is ${MAX_FILE_SIZE} bytes`,
        }),
      };
    }

    if (fileBuffer.length === 0) {
      return {
        statusCode: 400,
        headers: responseHeaders,
        body: JSON.stringify({ error: 'File content is empty' }),
      };
    }

    // 8. Generate a unique, non-guessable S3 key to prevent overwrites
    const uniqueId = crypto.randomUUID();
    const timestamp = new Date().toISOString().split('T')[0];
    const s3Key = `uploads/${timestamp}/${uniqueId}/${sanitizedFilename}`;

    // 9. Upload to S3 with restricted settings
    const putCommand = new PutObjectCommand({
      Bucket: BUCKET_NAME,
      Key: s3Key,
      Body: fileBuffer,
      ContentType: contentType.toLowerCase().split(';')[0].trim(),
      // Server-side encryption at rest
      ServerSideEncryption: 'AES256',
      // Metadata for audit trail
      Metadata: {
        'uploaded-by': 'api-upload',
        'original-filename': sanitizedFilename,
        'upload-timestamp': new Date().toISOString(),
        'source-ip': rateLimitKey(event),
      },
    });

    await s3Client.send(putCommand);

    console.log(JSON.stringify({
      action: 'file_uploaded',
      s3Key,
      contentType: contentType.toLowerCase().split(';')[0].trim(),
      fileSize: fileBuffer.length,
      sourceIp: rateLimitKey(event),
      timestamp: new Date().toISOString(),
    }));

    return {
      statusCode: 200,
      headers: responseHeaders,
      body: JSON.stringify({
        message: 'File uploaded successfully',
        key: s3Key,
        size: fileBuffer.length,
      }),
    };
  } catch (error) {
    // Don't leak internal error details to clients
    console.error('Upload error:', error);
    return {
      statusCode: 500,
      headers: responseHeaders,
      body: JSON.stringify({ error: 'Internal server error' }),
    };
  }
};

